<?php
namespace App\Http\Controllers\AdminUtama;
use App\Actions\AdminUtama\SanitizeNarrativeContent;use App\Http\Controllers\Controller;use App\Models\{ApiRequestLog,KbliReference,Permission,RegionReference,Role,SecurityEventLog,User};use App\Services\AdminUtama\AdminAuditService;use Illuminate\Http\Request;
class AdminUtamaController extends Controller { public function dashboard(){ $data=['users'=>User::query()->count(),'roles'=>Role::query()->count(),'permissions'=>Permission::query()->count(),'security_events'=>SecurityEventLog::query()->count()]; return view('pages.admin-utama.dashboard',compact('data')); } public function accounts(){ return view('pages.admin-utama.accounts',['accounts'=>User::query()->latest()->limit(25)->get(['id','name','email','account_type','is_active'])]); } public function roles(){ return view('pages.admin-utama.roles',['roles'=>Role::query()->withCount('permissions')->get()]); } public function permissions(){ return view('pages.admin-utama.permissions',['permissions'=>Permission::query()->orderBy('module')->get()]); } public function settings(){ return view('pages.admin-utama.settings'); } public function kbliReferences(){ return view('pages.admin-utama.kbli',['kbli'=>KbliReference::query()->latest()->limit(50)->get(['id','kbli_code','title','is_active'])]); } public function regions(){ return view('pages.admin-utama.regions',['regions'=>RegionReference::query()->latest()->limit(50)->get(['id','region_code','region_name','region_level','is_active'])]); } public function surveySettings(){ return view('pages.admin-utama.survey-settings'); } public function expertInstrumentSettings(){ return view('pages.admin-utama.expert-settings'); } public function announcements(){ return view('pages.admin-utama.announcements'); } public function securityLogs(){ return view('pages.admin-utama.security-logs',['securityEvents'=>SecurityEventLog::query()->latest()->limit(50)->get(['id','event_type','severity','event_time']),'apiLogs'=>ApiRequestLog::query()->latest()->limit(50)->get(['id','method','endpoint','http_status','requested_at'])]); } public function storeAnnouncement(Request $request, SanitizeNarrativeContent $sanitizeNarrativeContent, AdminAuditService $audit){ $payload=$request->validate(['title'=>['required','string','max:150'],'content'=>['required','string']]); $sanitized=$sanitizeNarrativeContent->execute($payload['content']); $audit->logManagementChange($request,'announcement.update','announcement',null,[],['title'=>$payload['title'],'content'=>$sanitized]); return back()->with('status','Konten berhasil disanitasi dan dicatat audit.'); }}
